mapper.select:

where id = #{id}
  and channel_type = 'telegram'
  and del_flag = '0'

channel_type = 'telegram' and del_flag = '0'
and (name like concat('%', #{name}, '%') or create_by like concat('%', #{name}, '%'))
and enabled = #{enabled}
and create_by = #{params.currentUsername}
order by update_time desc, create_time desc, id desc

select ac.app_id, c.id, c.channel_type, c.access_mode, c.name, c.bot_token, c.chat_id, c.enabled, c.del_flag, c.create_by, c.create_time, c.update_by, c.update_time, c.remark from monitor_alert_channel c inner join monitor_app_alert_channel ac on ac.channel_id = c.id where ac.app_id in
#{appId}
and c.channel_type = 'telegram' and c.del_flag = '0' order by ac.app_id asc, c.enabled desc, c.update_time desc, c.create_time desc, c.id desc
